--
-- Table structure for table `AuthUser`
--

DROP TABLE IF EXISTS `AuthUser`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `AuthUser` (
  `id` varchar(191) COLLATE utf8mb4_unicode_ci NOT NULL,
  `username` varchar(191) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `email` varchar(191) COLLATE utf8mb4_unicode_ci NOT NULL,
  `passwordHash` varchar(191) COLLATE utf8mb4_unicode_ci NOT NULL,
  `role` enum('SUPERADMIN','BP','FRANCHISE','CENTER','TEACHER','STUDENT') COLLATE utf8mb4_unicode_ci NOT NULL,
  `isActive` tinyint(1) NOT NULL DEFAULT '1',
  `failedAttempts` int NOT NULL DEFAULT '0',
  `lockUntil` datetime(3) DEFAULT NULL,
  `mustChangePassword` tinyint(1) NOT NULL DEFAULT '0',
  `tenantId` varchar(191) COLLATE utf8mb4_unicode_ci NOT NULL,
  `parentUserId` varchar(191) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `hierarchyNodeId` varchar(191) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `studentId` varchar(191) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `createdAt` datetime(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3),
  `updatedAt` datetime(3) NOT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `AuthUser_tenantId_email_key` (`tenantId`,`email`),
  UNIQUE KEY `AuthUser_studentId_key` (`studentId`),
  UNIQUE KEY `AuthUser_tenantId_username_key` (`tenantId`,`username`),
  KEY `AuthUser_tenantId_idx` (`tenantId`),
  KEY `AuthUser_username_idx` (`username`),
  KEY `AuthUser_tenantId_role_idx` (`tenantId`,`role`),
  KEY `AuthUser_parentUserId_idx` (`parentUserId`),
  KEY `AuthUser_role_idx` (`role`),
  KEY `AuthUser_hierarchyNodeId_idx` (`hierarchyNodeId`),
  KEY `AuthUser_tenantId_createdAt_id_idx` (`tenantId`,`createdAt`,`id`),
  KEY `AuthUser_tenantId_role_createdAt_idx` (`tenantId`,`role`,`createdAt`),
  CONSTRAINT `AuthUser_hierarchyNodeId_fkey` FOREIGN KEY (`hierarchyNodeId`) REFERENCES `HierarchyNode` (`id`) ON DELETE SET NULL ON UPDATE CASCADE,
  CONSTRAINT `AuthUser_parentUserId_fkey` FOREIGN KEY (`parentUserId`) REFERENCES `AuthUser` (`id`) ON DELETE SET NULL ON UPDATE CASCADE,
  CONSTRAINT `AuthUser_studentId_fkey` FOREIGN KEY (`studentId`) REFERENCES `Student` (`id`) ON DELETE SET NULL ON UPDATE CASCADE,
  CONSTRAINT `AuthUser_tenantId_fkey` FOREIGN KEY (`tenantId`) REFERENCES `Tenant` (`id`) ON DELETE RESTRICT ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

