CREATE TABLE `Batch` (
  `id` varchar(191) COLLATE utf8mb4_unicode_ci NOT NULL,
  `tenantId` varchar(191) COLLATE utf8mb4_unicode_ci NOT NULL,
  `hierarchyNodeId` varchar(191) COLLATE utf8mb4_unicode_ci NOT NULL,
  `name` varchar(191) COLLATE utf8mb4_unicode_ci NOT NULL,
  `schedule` json DEFAULT NULL,
  `status` enum('ACTIVE','INACTIVE','ARCHIVED') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'ACTIVE',
  `isActive` tinyint(1) NOT NULL DEFAULT '1',
  `createdAt` datetime(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3),
  `updatedAt` datetime(3) NOT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `Batch_tenantId_hierarchyNodeId_name_key` (`tenantId`,`hierarchyNodeId`,`name`),
  KEY `Batch_tenantId_hierarchyNodeId_status_isActive_idx` (`tenantId`,`hierarchyNodeId`,`status`,`isActive`),
  KEY `Batch_hierarchyNodeId_createdAt_idx` (`hierarchyNodeId`,`createdAt`),
  CONSTRAINT `Batch_hierarchyNodeId_fkey` FOREIGN KEY (`hierarchyNodeId`) REFERENCES `HierarchyNode` (`id`) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT `Batch_tenantId_fkey` FOREIGN KEY (`tenantId`) REFERENCES `Tenant` (`id`) ON DELETE RESTRICT ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
