--
-- Table structure for table `QuestionBank`
--

DROP TABLE IF EXISTS `QuestionBank`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `QuestionBank` (
  `id` varchar(191) COLLATE utf8mb4_unicode_ci NOT NULL,
  `tenantId` varchar(191) COLLATE utf8mb4_unicode_ci NOT NULL,
  `levelId` varchar(191) COLLATE utf8mb4_unicode_ci NOT NULL,
  `templateId` varchar(191) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `difficulty` enum('EASY','MEDIUM','HARD') COLLATE utf8mb4_unicode_ci NOT NULL,
  `prompt` varchar(191) COLLATE utf8mb4_unicode_ci NOT NULL,
  `operands` json NOT NULL,
  `operation` varchar(191) COLLATE utf8mb4_unicode_ci NOT NULL,
  `correctAnswer` int NOT NULL,
  `isActive` tinyint(1) NOT NULL DEFAULT '1',
  `createdAt` datetime(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3),
  `updatedAt` datetime(3) NOT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `QuestionBank_tenantId_levelId_prompt_key` (`tenantId`,`levelId`,`prompt`),
  KEY `QuestionBank_tenantId_levelId_difficulty_isActive_idx` (`tenantId`,`levelId`,`difficulty`,`isActive`),
  KEY `QuestionBank_templateId_idx` (`templateId`),
  KEY `QuestionBank_levelId_fkey` (`levelId`),
  CONSTRAINT `QuestionBank_levelId_fkey` FOREIGN KEY (`levelId`) REFERENCES `Level` (`id`) ON DELETE RESTRICT ON UPDATE CASCADE,
  CONSTRAINT `QuestionBank_templateId_fkey` FOREIGN KEY (`templateId`) REFERENCES `WorksheetTemplate` (`id`) ON DELETE SET NULL ON UPDATE CASCADE,
  CONSTRAINT `QuestionBank_tenantId_fkey` FOREIGN KEY (`tenantId`) REFERENCES `Tenant` (`id`) ON DELETE RESTRICT ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

