DROP TABLE IF EXISTS `WorksheetAssignment`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `WorksheetAssignment` (
  `tenantId` varchar(191) COLLATE utf8mb4_unicode_ci NOT NULL,
  `worksheetId` varchar(191) COLLATE utf8mb4_unicode_ci NOT NULL,
  `studentId` varchar(191) COLLATE utf8mb4_unicode_ci NOT NULL,
  `createdByUserId` varchar(191) COLLATE utf8mb4_unicode_ci NOT NULL,
  `assignedAt` datetime(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3),
  `dueDate` datetime(3) DEFAULT NULL,
  `unassignedAt` datetime(3) DEFAULT NULL,
  `isActive` tinyint(1) NOT NULL DEFAULT '1',
  PRIMARY KEY (`worksheetId`,`studentId`),
  KEY `WorksheetAssignment_tenantId_studentId_assignedAt_idx` (`tenantId`,`studentId`,`assignedAt`),
  KEY `WorksheetAssignment_tenantId_studentId_dueDate_idx` (`tenantId`,`studentId`,`dueDate`),
  KEY `WorksheetAssignment_tenantId_worksheetId_idx` (`tenantId`,`worksheetId`),
  KEY `WorksheetAssignment_studentId_fkey` (`studentId`),
  KEY `WorksheetAssignment_createdByUserId_fkey` (`createdByUserId`),
  CONSTRAINT `WorksheetAssignment_createdByUserId_fkey` FOREIGN KEY (`createdByUserId`) REFERENCES `AuthUser` (`id`) ON DELETE RESTRICT ON UPDATE CASCADE,
  CONSTRAINT `WorksheetAssignment_studentId_fkey` FOREIGN KEY (`studentId`) REFERENCES `Student` (`id`) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT `WorksheetAssignment_tenantId_fkey` FOREIGN KEY (`tenantId`) REFERENCES `Tenant` (`id`) ON DELETE RESTRICT ON UPDATE CASCADE,
  CONSTRAINT `WorksheetAssignment_worksheetId_fkey` FOREIGN KEY (`worksheetId`) REFERENCES `Worksheet` (`id`) ON DELETE CASCADE ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
