DROP TABLE IF EXISTS `WorksheetQuestion`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `WorksheetQuestion` (
  `id` varchar(191) COLLATE utf8mb4_unicode_ci NOT NULL,
  `tenantId` varchar(191) COLLATE utf8mb4_unicode_ci NOT NULL,
  `worksheetId` varchar(191) COLLATE utf8mb4_unicode_ci NOT NULL,
  `questionBankId` varchar(191) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `questionNumber` int NOT NULL,
  `operands` json NOT NULL,
  `operation` varchar(191) COLLATE utf8mb4_unicode_ci NOT NULL,
  `correctAnswer` int NOT NULL,
  `createdAt` datetime(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3),
  PRIMARY KEY (`id`),
  UNIQUE KEY `WorksheetQuestion_worksheetId_questionNumber_key` (`worksheetId`,`questionNumber`),
  KEY `WorksheetQuestion_tenantId_worksheetId_idx` (`tenantId`,`worksheetId`),
  KEY `WorksheetQuestion_questionBankId_idx` (`questionBankId`),
  CONSTRAINT `WorksheetQuestion_questionBankId_fkey` FOREIGN KEY (`questionBankId`) REFERENCES `QuestionBank` (`id`) ON DELETE SET NULL ON UPDATE CASCADE,
  CONSTRAINT `WorksheetQuestion_tenantId_fkey` FOREIGN KEY (`tenantId`) REFERENCES `Tenant` (`id`) ON DELETE RESTRICT ON UPDATE CASCADE,
  CONSTRAINT `WorksheetQuestion_worksheetId_fkey` FOREIGN KEY (`worksheetId`) REFERENCES `Worksheet` (`id`) ON DELETE CASCADE ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

